import{_ as n,o as s,c as a,b as t}from"./app.d05353ee.js";const e={},o=t(`<p>Below is the full, updated documentation with the &quot;Comparison with Other Frameworks&quot; section moved to the top and the &quot;Introduction&quot; section renamed to &quot;Basics&quot;:</p><hr><h1 id="context" tabindex="-1"><a class="header-anchor" href="#context" aria-hidden="true">#</a> Context</h1><h2 id="comparison-with-other-frameworks" tabindex="-1"><a class="header-anchor" href="#comparison-with-other-frameworks" aria-hidden="true">#</a> Comparison with Other Frameworks</h2><p>In many other web frameworks, such as Ruby on Rails and Laravel, dependency injection is typically handled through a service container. These frameworks use a central registry to resolve dependencies automatically. In contrast, Go\u2019s approach with <code>context.Context</code> is more explicit. While it requires passing context manually, it avoids hidden dependencies and global state, making applications easier to understand and test.</p><h2 id="basics" tabindex="-1"><a class="header-anchor" href="#basics" aria-hidden="true">#</a> Basics</h2><p>You can use Go&#39;s <code>context.Context</code> to manage dependencies and handle dependency injection in a structured and idiomatic way. Dependency injection is a design pattern where struct dependencies are provided externally rather than created inside the struct itself.</p><p>Let&#39;s look at a simple example:</p><div class="language-go ext-go line-numbers-mode"><pre class="language-go"><code>ctx <span class="token operator">:=</span> request<span class="token punctuation">.</span><span class="token function">Context</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
ctx <span class="token operator">=</span> context<span class="token punctuation">.</span><span class="token function">WithValue</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> <span class="token string">&quot;userRepository&quot;</span><span class="token punctuation">,</span> <span class="token function">NewUserRepository</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>In this example, the <code>User</code> struct needs to retrieve users from a data source. We <strong>inject</strong> a service that retrieves users via <code>context.WithValue</code>, allowing us to easily swap out implementations or mock dependencies for testing.</p><h2 id="using-context-for-dependency-injection" tabindex="-1"><a class="header-anchor" href="#using-context-for-dependency-injection" aria-hidden="true">#</a> Using Context for Dependency Injection</h2><h3 id="adding-values-to-context" tabindex="-1"><a class="header-anchor" href="#adding-values-to-context" aria-hidden="true">#</a> Adding Values to Context</h3><p>You can add dependencies to a <code>context.Context</code> instance using <code>context.WithValue</code>:</p><div class="language-go ext-go line-numbers-mode"><pre class="language-go"><code>ctx <span class="token operator">:=</span> context<span class="token punctuation">.</span><span class="token function">WithValue</span><span class="token punctuation">(</span>request<span class="token punctuation">.</span><span class="token function">Context</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token string">&quot;db&quot;</span><span class="token punctuation">,</span> <span class="token function">NewDatabaseConnection</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>This allows you to pass dependencies down through the request lifecycle without modifying function signatures.</p><h3 id="retrieving-values-from-context" tabindex="-1"><a class="header-anchor" href="#retrieving-values-from-context" aria-hidden="true">#</a> Retrieving Values from Context</h3><p>To access values stored in the context, use <code>request.Context().Value</code>:</p><div class="language-go ext-go line-numbers-mode"><pre class="language-go"><code>db <span class="token operator">:=</span> request<span class="token punctuation">.</span><span class="token function">Context</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Value</span><span class="token punctuation">(</span><span class="token string">&quot;db&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token punctuation">(</span><span class="token operator">*</span>DatabaseConnection<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="passing-context-in-controllers" tabindex="-1"><a class="header-anchor" href="#passing-context-in-controllers" aria-hidden="true">#</a> Passing Context in Controllers</h3><p>When handling HTTP requests in a controller, extract the context from the request:</p><div class="language-go ext-go line-numbers-mode"><pre class="language-go"><code><span class="token keyword">func</span> <span class="token function">Contact</span><span class="token punctuation">(</span>response http<span class="token punctuation">.</span>ResponseWriter<span class="token punctuation">,</span> request <span class="token operator">*</span>http<span class="token punctuation">.</span>Request<span class="token punctuation">)</span> <span class="token builtin">error</span> <span class="token punctuation">{</span>
    ctx <span class="token operator">:=</span> request<span class="token punctuation">.</span><span class="token function">Context</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
    userRepo <span class="token operator">:=</span> ctx<span class="token punctuation">.</span><span class="token function">Value</span><span class="token punctuation">(</span><span class="token string">&quot;userRepository&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token punctuation">(</span>UserRepository<span class="token punctuation">)</span>
    users <span class="token operator">:=</span> userRepo<span class="token punctuation">.</span><span class="token function">GetAll</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
    <span class="token keyword">return</span> json<span class="token punctuation">.</span><span class="token function">NewEncoder</span><span class="token punctuation">(</span>response<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Encode</span><span class="token punctuation">(</span>users<span class="token punctuation">)</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="passing-context-to-multiple-methods" tabindex="-1"><a class="header-anchor" href="#passing-context-to-multiple-methods" aria-hidden="true">#</a> Passing Context to Multiple Methods</h2><p>In most cases, context needs to be passed deeper into the application. This ensures that dependencies remain accessible throughout different layers of the application.</p><div class="language-go ext-go line-numbers-mode"><pre class="language-go"><code><span class="token keyword">func</span> <span class="token function">CreateUser</span><span class="token punctuation">(</span>response http<span class="token punctuation">.</span>ResponseWriter<span class="token punctuation">,</span> request <span class="token operator">*</span>http<span class="token punctuation">.</span>Request<span class="token punctuation">)</span> <span class="token builtin">error</span> <span class="token punctuation">{</span>
    ctx <span class="token operator">:=</span> request<span class="token punctuation">.</span><span class="token function">Context</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
    users<span class="token punctuation">,</span> err <span class="token operator">:=</span> <span class="token function">processBusinessLogic</span><span class="token punctuation">(</span>ctx<span class="token punctuation">)</span>
    <span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span>
        <span class="token keyword">return</span> err
    <span class="token punctuation">}</span>
    <span class="token keyword">return</span> json<span class="token punctuation">.</span><span class="token function">NewEncoder</span><span class="token punctuation">(</span>response<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Encode</span><span class="token punctuation">(</span>users<span class="token punctuation">)</span>
<span class="token punctuation">}</span>

<span class="token keyword">func</span> <span class="token function">processBusinessLogic</span><span class="token punctuation">(</span>ctx context<span class="token punctuation">.</span>Context<span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span>User<span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    db<span class="token punctuation">,</span> ok <span class="token operator">:=</span> ctx<span class="token punctuation">.</span><span class="token function">Value</span><span class="token punctuation">(</span><span class="token string">&quot;db&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token punctuation">(</span><span class="token operator">*</span>DatabaseConnection<span class="token punctuation">)</span>
    <span class="token keyword">if</span> <span class="token operator">!</span>ok <span class="token punctuation">{</span>
        <span class="token keyword">return</span> <span class="token boolean">nil</span><span class="token punctuation">,</span> errors<span class="token punctuation">.</span><span class="token function">New</span><span class="token punctuation">(</span><span class="token string">&quot;database connection not found in context&quot;</span><span class="token punctuation">)</span>
    <span class="token punctuation">}</span>
    users <span class="token operator">:=</span> <span class="token function">fetchUsers</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> db<span class="token punctuation">)</span>
    <span class="token keyword">return</span> users<span class="token punctuation">,</span> <span class="token boolean">nil</span>
<span class="token punctuation">}</span>

<span class="token keyword">func</span> <span class="token function">fetchUsers</span><span class="token punctuation">(</span>ctx context<span class="token punctuation">.</span>Context<span class="token punctuation">,</span> db <span class="token operator">*</span>DatabaseConnection<span class="token punctuation">)</span> <span class="token punctuation">[</span><span class="token punctuation">]</span>User <span class="token punctuation">{</span>
    <span class="token keyword">return</span> db<span class="token punctuation">.</span><span class="token function">GetUsers</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>This pattern ensures that all methods have access to the necessary dependencies without relying on global state.</p><h2 id="binding-dependencies" tabindex="-1"><a class="header-anchor" href="#binding-dependencies" aria-hidden="true">#</a> Binding Dependencies</h2><h3 id="singleton-dependencies" tabindex="-1"><a class="header-anchor" href="#singleton-dependencies" aria-hidden="true">#</a> Singleton Dependencies</h3><p>For dependencies that should persist throughout the application lifecycle (not only the request lifecycle), create a package <code>singleton</code> and call <code>singleton.Boot()</code> in <code>cmd/api/main.go</code> before we handle the commands (and requests):</p><div class="language-go ext-go line-numbers-mode"><pre class="language-go"><code><span class="token keyword">package</span> singleton

<span class="token keyword">import</span> <span class="token punctuation">(</span>
	<span class="token string">&quot;context&quot;</span>
	<span class="token string">&quot;time&quot;</span>
<span class="token punctuation">)</span>

<span class="token keyword">var</span> Ctx context<span class="token punctuation">.</span>Context

<span class="token keyword">func</span> <span class="token function">init</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    Ctx <span class="token operator">=</span> context<span class="token punctuation">.</span><span class="token function">Background</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token punctuation">}</span>

<span class="token keyword">func</span> <span class="token function">Boot</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    Ctx <span class="token operator">=</span> context<span class="token punctuation">.</span><span class="token function">WithValue</span><span class="token punctuation">(</span>Ctx<span class="token punctuation">,</span> <span class="token string">&quot;app_started_at&quot;</span><span class="token punctuation">,</span> time<span class="token punctuation">.</span><span class="token function">Now</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="accessing-the-singleton-value" tabindex="-1"><a class="header-anchor" href="#accessing-the-singleton-value" aria-hidden="true">#</a> Accessing the Singleton Value</h4><p>Anywhere in your code, you can import the <code>singleton</code> package and use <code>singleton.Ctx</code> to retrieve the global context. For example, in an HTTP handler you might want to show when the application started:</p><div class="language-go ext-go line-numbers-mode"><pre class="language-go"><code><span class="token keyword">package</span> handler

<span class="token keyword">import</span> <span class="token punctuation">(</span>
	<span class="token string">&quot;fmt&quot;</span>
	<span class="token string">&quot;net/http&quot;</span>
	<span class="token string">&quot;time&quot;</span>
	<span class="token string">&quot;myapp/singleton&quot;</span>
<span class="token punctuation">)</span>

<span class="token keyword">func</span> <span class="token function">PrintStartedAt</span><span class="token punctuation">(</span>w http<span class="token punctuation">.</span>ResponseWriter<span class="token punctuation">,</span> r <span class="token operator">*</span>http<span class="token punctuation">.</span>Request<span class="token punctuation">)</span> <span class="token builtin">error</span> <span class="token punctuation">{</span>
    <span class="token comment">// Retrieve the application start time from the global context.</span>
    startTime<span class="token punctuation">,</span> ok <span class="token operator">:=</span> singleton<span class="token punctuation">.</span>Ctx<span class="token punctuation">.</span><span class="token function">Value</span><span class="token punctuation">(</span><span class="token string">&quot;app_started_at&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token punctuation">(</span>time<span class="token punctuation">.</span>Time<span class="token punctuation">)</span>
    <span class="token keyword">if</span> <span class="token operator">!</span>ok <span class="token punctuation">{</span>
        <span class="token keyword">return</span> handler<span class="token punctuation">.</span><span class="token function">NewSystemError</span><span class="token punctuation">(</span><span class="token builtin">error</span><span class="token punctuation">.</span><span class="token function">New</span><span class="token punctuation">(</span><span class="token string">&quot;Application start time unavailable&quot;</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token string">&quot;processing_error&quot;</span><span class="token punctuation">)</span>
    <span class="token punctuation">}</span>
    
    fmt<span class="token punctuation">.</span><span class="token function">Fprintf</span><span class="token punctuation">(</span>w<span class="token punctuation">,</span> <span class="token string">&quot;Application started at: %v&quot;</span><span class="token punctuation">,</span> startTime<span class="token punctuation">)</span>

    <span class="token keyword">return</span> <span class="token boolean">nil</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="using-context-in-middleware" tabindex="-1"><a class="header-anchor" href="#using-context-in-middleware" aria-hidden="true">#</a> Using Context in Middleware</h3><p>Middleware can be used to inject dependencies dynamically into the request context. Below is the simplified middleware example that generates a random request ID using a random string and attaches it to the context.</p><div class="language-go ext-go line-numbers-mode"><pre class="language-go"><code><span class="token keyword">package</span> middleware

<span class="token keyword">import</span> <span class="token punctuation">(</span>
	<span class="token string">&quot;context&quot;</span>
	<span class="token string">&quot;fmt&quot;</span>
	<span class="token string">&quot;math/rand&quot;</span>
	<span class="token string">&quot;net/http&quot;</span>

	<span class="token string">&quot;src/internal/pkg/handler&quot;</span>
<span class="token punctuation">)</span>

<span class="token comment">// RequestIDMiddleware adds a unique request ID to the context for each request.</span>
<span class="token keyword">type</span> RequestIDMiddleware <span class="token keyword">struct</span><span class="token punctuation">{</span><span class="token punctuation">}</span>

<span class="token comment">// Handle generates a random request ID and attaches it to the context.</span>
<span class="token keyword">func</span> <span class="token punctuation">(</span>m RequestIDMiddleware<span class="token punctuation">)</span> <span class="token function">Handle</span><span class="token punctuation">(</span>next handler<span class="token punctuation">.</span>Controller<span class="token punctuation">)</span> handler<span class="token punctuation">.</span>Controller <span class="token punctuation">{</span>
	<span class="token keyword">return</span> <span class="token keyword">func</span><span class="token punctuation">(</span>response http<span class="token punctuation">.</span>ResponseWriter<span class="token punctuation">,</span> request <span class="token operator">*</span>http<span class="token punctuation">.</span>Request<span class="token punctuation">)</span> <span class="token builtin">error</span> <span class="token punctuation">{</span>
		<span class="token comment">// Generate a random request ID.</span>
		reqID <span class="token operator">:=</span> fmt<span class="token punctuation">.</span><span class="token function">Sprintf</span><span class="token punctuation">(</span><span class="token string">&quot;req-%d&quot;</span><span class="token punctuation">,</span> rand<span class="token punctuation">.</span><span class="token function">Intn</span><span class="token punctuation">(</span><span class="token number">1000000</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
		<span class="token comment">// Attach the request ID to the request context.</span>
		ctx <span class="token operator">:=</span> context<span class="token punctuation">.</span><span class="token function">WithValue</span><span class="token punctuation">(</span>request<span class="token punctuation">.</span><span class="token function">Context</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token string">&quot;requestID&quot;</span><span class="token punctuation">,</span> reqID<span class="token punctuation">)</span>
		<span class="token comment">// Proceed with the next handler, passing the modified request.</span>
		<span class="token keyword">return</span> <span class="token function">next</span><span class="token punctuation">(</span>response<span class="token punctuation">,</span> request<span class="token punctuation">.</span><span class="token function">WithContext</span><span class="token punctuation">(</span>ctx<span class="token punctuation">)</span><span class="token punctuation">)</span>
	<span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="resolving-dependencies" tabindex="-1"><a class="header-anchor" href="#resolving-dependencies" aria-hidden="true">#</a> Resolving Dependencies</h2><h3 id="resolving-from-context" tabindex="-1"><a class="header-anchor" href="#resolving-from-context" aria-hidden="true">#</a> Resolving from Context</h3><p>Retrieve values from the context:</p><div class="language-go ext-go line-numbers-mode"><pre class="language-go"><code>logger <span class="token operator">:=</span> request<span class="token punctuation">.</span><span class="token function">Context</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Value</span><span class="token punctuation">(</span><span class="token string">&quot;logger&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token punctuation">(</span>Logger<span class="token punctuation">)</span>
logger<span class="token punctuation">.</span><span class="token function">Log</span><span class="token punctuation">(</span><span class="token string">&quot;Application started&quot;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="handling-missing-values-gracefully" tabindex="-1"><a class="header-anchor" href="#handling-missing-values-gracefully" aria-hidden="true">#</a> Handling Missing Values Gracefully</h3><p>Since <code>ctx.Value</code> returns <code>interface{}</code>, always check for <code>nil</code> before type assertion:</p><div class="language-go ext-go line-numbers-mode"><pre class="language-go"><code><span class="token keyword">if</span> val <span class="token operator">:=</span> request<span class="token punctuation">.</span><span class="token function">Context</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Value</span><span class="token punctuation">(</span><span class="token string">&quot;nonexistentKey&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> val <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span>
    value <span class="token operator">:=</span> val<span class="token punctuation">.</span><span class="token punctuation">(</span><span class="token builtin">string</span><span class="token punctuation">)</span>
    fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span>value<span class="token punctuation">)</span>
<span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
    fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;Key not found in context&quot;</span><span class="token punctuation">)</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,42),p=[o];function c(i,u){return s(),a("div",null,p)}const r=n(e,[["render",c],["__file","container.html.vue"]]);export{r as default};
